public static string Pascalize(this string input)
{
    // Anti-pattern: .Value.ToUpper() per regex match allocates a string per match
    return WordPartsRegex().Replace(input, match =>
        match.Value.Substring(0, 1).ToUpper() + match.Value.Substring(1));
}

arguments.new_str:
public static string Pascalize(this string input)
{
    var matches = WordPartsRegex().Matches(input);
    if (matches.Count == 0)
    {
        return input;
    }

    // Pre-calculate length to allocate once
    var totalLength = 0;
    foreach (Match m in matches)
    {
        totalLength += m.Length;
    }

    return string.Create(totalLength, (input, matches), static (span, state) =>
    {
        var pos = 0;
        foreach (Match m in state.matches)
        {
            span[pos] = char.ToUpperInvariant(state.input[m.Index]);
            state.input.AsSpan(m.Index + 1, m.Length - 1).CopyTo(span[(pos + 1)..]);
            pos += m.Length;
        }
    });
}

