public InflectionRule(string pattern, string replacement)
{
    // IgnoreCase only — avoid RegexOptions.Compiled to reduce JIT overhead
    // when many rules are created at startup. For short strings, interpreted
    // regex performance is comparable.
    _regex = new Regex(pattern, RegexOptions.IgnoreCase);
    _replacement = replacement;
}

/// <summary>
/// Attempts to apply this rule to the given word.
/// </summary>
/// <param name="word">The word to transform.</param>
/// <returns>The transformed word if the pattern matches; otherwise, null.</returns>
public string? Apply(string word)
{
    // Single regex pass: Replace returns the original string reference when
    // there is no match, so a reference comparison avoids running the regex twice.
    var result = _regex.Replace(word, _replacement);
    return ReferenceEquals(result, word) ? null : result;
}

